mapper.select:
select id, owner_id, owner_name, praise_type, praise_target,
       status, content, create_time, update_time, remark
from community_property_praise
where owner_id = #{ownerId}
  and owner_name like concat('%', #{ownerName}, '%')
  and praise_type = #{praiseType}
  and praise_target like concat('%', #{praiseTarget}, '%')
  and status = #{status}
order by create_time desc

mapper.insert:
insert into community_property_praise (
    owner_id, owner_name, praise_type, praise_content,
    praise_target, status, reply_content, reply_time,
    community_id, create_by, create_time, update_by, update_time, remark
) values (
             #{ownerId}, #{ownerName}, #{praiseType}, #{praiseContent},
             #{praiseTarget}, #{status}, #{replyContent}, #{replyTime},
             #{communityId}, #{createBy}, #{createTime}, #{updateBy}, #{updateTime}, #{remark}
         )
